sql:
SELECT driver_id, actual_tonnes, percent_difference
FROM capacity_data
WHERE percent_difference < 0;

SELECT 
    (SELECT AVG(percent_difference) FROM capacity_data) AS average_capacity_difference,
    (SELECT MAX(overall_difference) FROM performance_metrics) AS max_overall_difference;

SELECT COUNT(DISTINCT center_id) 
FROM capacity_data 
WHERE percent_difference_positive > 0.05;

SELECT driver_name, years_of_experience
FROM drivers
WHERE rating > (SELECT AVG(rating) FROM drivers);

SELECT forecast_id, date, predicted_capacity
FROM capacity_forecasts
WHERE date = '2023-05-03';

SELECT center_name, location
FROM logistics_centers
WHERE capacity > (SELECT AVG(capacity) FROM logistics_centers);

external_knowledge:
- Overload: Refers to a situation where the actual tonnes transported exceed the nominal capacity;
- Heart of Miami, FL: Refers to logistics centers located in Miami, FL;
- Heavy trucks: Refers to the transport mode named 'Truck';
- Advertised strength: Refers to the nominal capacity of the transportation mode.

- "captains" refers to the drivers or operators in the logistics domain;
- "harbor" signifies the department where the operations take place;
- "cargo" represents the actual tonnes transported by the logistics operations;
- "fluctuations in their voyages" indicates the percentage difference in performance compared to the nominal capacity;
- "docking station" is a metaphorical term for the logistics center.

sql:
SELECT date, predicted_capacity
FROM capacity_forecasts
WHERE historical_accuracy > (SELECT AVG(historical_accuracy) FROM capacity_forecasts);

external_knowledge:
- "shining stars" refers to the top performers in terms of transported tonnes;
- "carrying the most weight on their shoulders" is a metaphor for transporting the most tonnes;
- "top contenders" means the entities ranked among the first 10 based on their transported tonnes;
- The comparison is based on the total tonnes transported, with the highest transported tonnes ranked first.
